/**** EMAIL Workbench Customization ****/
SET search_path TO docwbmain;
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
DO $$ 
DECLARE
   new_tenant_id  VARCHAR(50);
BEGIN 
	VALUES (uuid_generate_v4(), (select 'Tenant '||count(*)+1 from tenant)) 
	RETURNING tenant_id into new_tenant_id;
	RAISE NOTICE '************************************';
	RAISE NOTICE 'New TenantId: %', new_tenant_id;
	RAISE NOTICE 'Please save this for future reference';
	RAISE NOTICE '************************************';
	
	--#TENANT 1 - Email Flow.
	
	
	
	
	
END $$;